<?php namespace App\Domains\Apparel\Services; class ClothingService { public function create(array $data) { return \App\Domains\Apparel\Models\Clothing::create($data); } public function update($id, array $data) { $clothing = \App\Domains\Apparel\Models\Clothing::find($id); return $clothing ? $clothing->update($data) : false; } public function delete($id) { return \App\Domains\Apparel\Models\Clothing::destroy($id); } public function list($tenantId) { return \App\Domains\Apparel\Models\Clothing::where('tenant_id', $tenantId)->get(); } }
